// Integration test for POST /api/route-plan — verifies the endpoint returns a
// valid weather-aware plan (legs + totals + per-leg warnings) for a short
// Mediterranean route off Barcelona.
async function testRoutePlanEndpoint() {
  const body = {
    points: [
      { lat: 41.35, lon: 2.17 },  // origin (boat)
      { lat: 41.55, lon: 2.55 },  // waypoint 1
      { lat: 41.80, lon: 3.10 }   // waypoint 2
    ],
    speed: 6
  };

  const res = await fetch('http://localhost:3001/api/route-plan', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body)
  });
  assertEquals(res.status, 200, 'Route plan should return 200');

  const data = await res.json();

  // Echoed speed + totals
  assertEquals(data.speed, 6, 'Echoes the requested speed');
  assert(data.totals && typeof data.totals.distanceNm === 'number', 'totals.distanceNm should be a number');
  assert(typeof data.totals.durationHours === 'number', 'totals.durationHours should be a number');
  assert(typeof data.totals.etaMs === 'number', 'totals.etaMs should be a number');
  assert(data.totals.etaMs > data.startTime, 'ETA should be after the start time');

  // Two legs for three points
  assert(Array.isArray(data.legs), 'legs should be an array');
  assertEquals(data.legs.length, 2, 'Three points form two legs');

  // Each leg carries geometry + weather assessment
  for (const leg of data.legs) {
    assert(typeof leg.distanceNm === 'number', 'leg.distanceNm should be a number');
    assert(typeof leg.bearing === 'number', 'leg.bearing should be a number');
    assert(typeof leg.bearingCompass === 'string' && leg.bearingCompass.length > 0, 'leg.bearingCompass should be a non-empty string');
    assert(typeof leg.durationHours === 'number', 'leg.durationHours should be a number');
    assert(['ok', 'caution', 'warning'].indexOf(leg.riskLevel) >= 0, 'leg.riskLevel should be a valid tier');
    assert(Array.isArray(leg.warnings), 'leg.warnings should be an array');
    // conditions is an object when weather resolved, or null when unavailable
    assert(leg.conditions === null || typeof leg.conditions === 'object', 'leg.conditions should be object or null');
  }

  // Total distance should be positive for this real multi-leg route
  assert(data.totals.distanceNm > 0, 'Total distance should be positive for a real route');
}

